// shadcn
import { Button } from "@/components/ui/button";

// constants
const imageItems = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/g3-1.jpg",
    title: "First one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/g3-2.jpg",
    title: "Second one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    id: 3,
    image: "https://cdn.uiable.com/block/g3-3.jpg",
    title: "Third one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    id: 4,
    image: "https://cdn.uiable.com/block/g3-4.jpg",
    title: "Fourth one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
];

//  ------------------------------ | GALLERY 3 | ------------------------------  //

export default function Gallery3() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14">
          <h2 className="text-foreground">Gallery</h2>
          <p className="mt-4 max-w-xl mx-auto text-muted-foreground">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-12 gap-6 items-stretch">
          {/* Left column: 2 stacked images */}
          <div className="col-span-12 md:col-span-5 flex flex-col gap-6">
            {/* First image with button in hover overlay */}
            <div className="relative overflow-hidden rounded-2xl cursor-pointer group min-h-64">
              <img
                src={imageItems[0].image}
                alt={imageItems[0].title}
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
              />
              <div className="absolute inset-0 bg-primary flex flex-col items-center justify-center text-center px-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300 gap-2">
                <h5 className="text-primary-foreground font-bold">
                  {imageItems[0].title}
                </h5>
                <p className="text-primary-foreground/90 text-sm">
                  {imageItems[0].description}
                </p>
                <Button className="bg-yellow-500 text-white hover:bg-yellow-500-600 mt-1">
                  Read More
                </Button>
              </div>
            </div>
            {/* Second image */}
            <div className="relative overflow-hidden rounded-2xl cursor-pointer group min-h-44">
              <img
                src={imageItems[3].image}
                alt={imageItems[3].title}
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
              />
              <div className="absolute inset-0 bg-primary flex flex-col items-center justify-center text-center px-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                <h5 className="text-primary-foreground font-bold mb-2">
                  {imageItems[3].title}
                </h5>
                <p className="text-primary-foreground/90 text-sm">
                  {imageItems[3].description}
                </p>
              </div>
            </div>
          </div>

          {/* Right column: 2 images top + promo card bottom */}
          <div className="col-span-12 md:col-span-7 flex flex-col gap-6">
            {/* Top: two unequal images */}
            <div className="grid grid-cols-12 gap-6 items-stretch h-44">
              <div className="col-span-7 relative overflow-hidden rounded-2xl cursor-pointer group">
                <img
                  src={imageItems[1].image}
                  alt={imageItems[1].title}
                  className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-primary flex flex-col items-center justify-center text-center px-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                  <h5 className="text-primary-foreground font-bold mb-2">
                    {imageItems[1].title}
                  </h5>
                  <p className="text-primary-foreground/90 text-sm">
                    {imageItems[1].description}
                  </p>
                </div>
              </div>
              <div className="col-span-5 relative overflow-hidden rounded-2xl cursor-pointer group">
                <img
                  src={imageItems[2].image}
                  alt={imageItems[2].title}
                  className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-primary flex flex-col items-center justify-center text-center px-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                  <h5 className="text-primary-foreground font-bold mb-2">
                    {imageItems[2].title}
                  </h5>
                  <p className="text-primary-foreground/90 text-sm">
                    {imageItems[2].description}
                  </p>
                </div>
              </div>
            </div>

            {/* Bottom: promo card — image with hover overlay */}
            <div className="flex-1 relative overflow-hidden rounded-2xl cursor-pointer group min-h-56">
              {/* Background image */}
              <img
                src={imageItems[3].image}
                alt="Product name"
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
              />
              {/* Hover overlay */}
              <div className="absolute inset-0 bg-primary flex flex-col items-center justify-center text-center px-8 gap-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                <h5 className="text-primary-foreground font-bold">
                  Product name
                </h5>
                <p className="text-primary-foreground/90 text-sm max-w-sm">
                  At half-past eight the door opened, the policeman appeared and
                  requesting them to follow him.
                </p>
                <Button className="bg-yellow-500 text-white hover:bg-yellow-600">
                  Primary
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
